import{_ as n,C as r,o as t,c as d,aQ as o,b as s,w as i,a as c,E as l,aR as p}from"./chunks/framework.cDvftfeu.js";const v=JSON.parse('{"title":"Ham Connect","description":"Ham Connect SSO platform overview and capabilities.","frontmatter":{"description":"Ham Connect SSO platform overview and capabilities.","prev":{"text":"Development Overview","link":"/en/developers/"},"next":{"text":"Integration Guide","link":"/en/developers/open-platform/oauth2-guide"}},"headers":[],"relativePath":"en/developers/open-platform/index.md","filePath":"en/developers/open-platform/index.md","lastUpdated":1777525243000}'),h={name:"en/developers/open-platform/index.md"};function u(m,e,f,b,A,g){const a=r("Mermaid");return t(),d("div",null,[e[1]||(e[1]=o('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /developers/open-platform.md for this page in Markdown format</div><h1 id="ham-connect" tabindex="-1">Ham Connect <a class="header-anchor" href="#ham-connect" aria-label="Permalink to &quot;Ham Connect&quot;">​</a></h1><p>Ham Connect is the OAuth 2.0 authorization service provided by the Ham Open Platform, allowing third-party applications to securely obtain authorized Ham user information.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Ham Connect is built on the standard <strong>OAuth 2.0 Authorization Code Grant</strong> (RFC 6749 §4.1). Third-party applications can implement &quot;Sign in with Ham&quot; functionality through Ham Connect to obtain basic user information after authorization.</p><h3 id="supported-scopes" tabindex="-1">Supported Scopes <a class="header-anchor" href="#supported-scopes" aria-label="Permalink to &quot;Supported Scopes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Scope</th><th>Description</th><th>Returned Fields</th></tr></thead><tbody><tr><td><code>profile</code></td><td>Access user nickname and avatar</td><td><code>nickname</code>, <code>avatar_url</code></td></tr><tr><td><code>is_student</code></td><td>Access whether the user is a student</td><td><code>is_student</code> (bool)</td></tr></tbody></table><blockquote><p><code>open_id</code> (the user&#39;s unique identifier within the current application) is always returned and does not require an additional scope.</p></blockquote><h2 id="oauth2-interaction-flow" tabindex="-1">OAuth2 Interaction Flow <a class="header-anchor" href="#oauth2-interaction-flow" aria-label="Permalink to &quot;OAuth2 Interaction Flow&quot;">​</a></h2>',9)),(t(),s(p,null,{default:i(()=>[l(a,{id:"mermaid-63",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%20%20%20%20participant%20U%20as%20User%0A%20%20%20%20participant%20TP%20as%20Third-party%20App%0A%20%20%20%20participant%20APP%20as%20Ham%0A%20%20%20%20participant%20BE%20as%20Ham%20Open%20Platform%0A%0A%20%20%20%20U-%3E%3ETP%3A%20Click%20%22Sign%20in%20with%20Ham%22%0A%20%20%20%20TP-%3E%3ETP%3A%20Generate%20random%20state%2C%20bind%20to%20session%0A%20%20%20%20TP-%3E%3EAPP%3A%20Open%20Universal%20Link%20to%20launch%20Ham%0A%20%20%20%20APP-%3E%3EU%3A%20Display%20authorization%20page%20(app%20info%20%2B%20scope%20list)%0A%20%20%20%20U-%3E%3EAPP%3A%20Tap%20%22Approve%22%0A%20%20%20%20APP-%3E%3ETP%3A%20Redirect%20to%20redirect_uri%20with%20code%20and%20state%0A%20%20%20%20TP-%3E%3ETP%3A%20Verify%20state%20consistency%0A%20%20%20%20TP-%3E%3EBE%3A%20POST%20%2Foauth%2Ftoken%20(code%20%2B%20client%20credentials)%0A%20%20%20%20BE-%3E%3ETP%3A%20Return%20access_token%0A%20%20%20%20TP-%3E%3EBE%3A%20GET%20%2Foauth%2Fuserinfo%20(Bearer%20token%20%2B%20client%20credentials)%0A%20%20%20%20BE-%3E%3ETP%3A%20Return%20open_id%20%2F%20nickname%20%2F%20avatar_url%20etc.%0A%20%20%20%20TP-%3E%3EU%3A%20Login%20successful%0A"})]),fallback:i(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h3 id="flow-description" tabindex="-1">Flow Description <a class="header-anchor" href="#flow-description" aria-label="Permalink to &quot;Flow Description&quot;">​</a></h3><ol><li><strong>Initiate Authorization</strong>: The third-party app launches Ham via Universal Link with <code>client_id</code>, <code>scope</code>, <code>state</code>, and <code>redirect_uri</code> parameters</li><li><strong>User Authorization</strong>: The user reviews the authorization details in Ham and approves</li><li><strong>Receive Authorization Code</strong>: Ham redirects to the third-party app&#39;s <code>redirect_uri</code> with a one-time <code>code</code></li><li><strong>Exchange Token</strong>: The third-party <strong>server</strong> exchanges the <code>code</code> + <code>client_id</code> + <code>client_secret</code> for an <code>access_token</code></li><li><strong>Fetch User Info</strong>: The third-party <strong>server</strong> uses the <code>access_token</code> + client credentials to request user information</li></ol><h3 id="key-endpoints" tabindex="-1">Key Endpoints <a class="header-anchor" href="#key-endpoints" aria-label="Permalink to &quot;Key Endpoints&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>https://ham.nowcent.cn/sso-authorize</code></td><td>Authorization entry (Universal Link), supports mobile, desktop (e.g. QR code scanning), and Passkey authentication</td></tr><tr><td><code>https://open-api.ham.nowcent.cn/oauth/token</code></td><td>Token exchange</td></tr><tr><td><code>https://open-api.ham.nowcent.cn/oauth/userinfo</code></td><td>Fetch user info</td></tr></tbody></table><h3 id="token-lifetime" tabindex="-1">Token Lifetime <a class="header-anchor" href="#token-lifetime" aria-label="Permalink to &quot;Token Lifetime&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Token</th><th>Lifetime</th><th>Notes</th></tr></thead><tbody><tr><td>Authorization Code</td><td>5 minutes</td><td>One-time use, invalidated after exchange</td></tr><tr><td>Access Token</td><td>2 hours</td><td>Re-authorization required after expiry</td></tr><tr><td>Refresh Token</td><td>Not provided</td><td>—</td></tr></tbody></table><h2 id="obtaining-client-id-and-client-secret" tabindex="-1">Obtaining client_id and client_secret <a class="header-anchor" href="#obtaining-client-id-and-client-secret" aria-label="Permalink to &quot;Obtaining client_id and client_secret&quot;">​</a></h2><p><code>client_id</code> and <code>client_secret</code> are the required credentials for integrating with Ham Connect:</p><ul><li><strong>client_id</strong>: The public identifier of the application, safe to use on the frontend</li><li><strong>client_secret</strong>: The confidential credential of the application, <strong>must only be used on the server side</strong> — never expose it in frontend code, mobile app bundles, or public repositories</li></ul><div class="warning custom-block"><p class="custom-block-title">How to Apply</p><p>Currently, <code>client_id</code> and <code>client_secret</code> must be obtained by contacting the developers.</p><p>Please reach out via <a href="https://github.com/whu-ham/whu-ham.github.io/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a> and provide the following information:</p><ol><li>Application name and description</li><li>Callback URL (<code>redirect_uri</code>) whitelist</li><li>Required scopes</li></ol></div><h2 id="security-notes" tabindex="-1">Security Notes <a class="header-anchor" href="#security-notes" aria-label="Permalink to &quot;Security Notes&quot;">​</a></h2><ul><li>All API calls must use <strong>HTTPS</strong></li><li><code>client_secret</code> and <code>access_token</code> must <strong>only be stored and used on the server side</strong></li><li>Always use and verify the <code>state</code> parameter to prevent CSRF attacks</li><li>Follow the <strong>principle of least privilege</strong> — only request the scopes your business needs</li><li>Use <code>open_id</code> as the unique user identifier; do not rely on <code>nickname</code> for uniqueness</li></ul><div class="tip custom-block"><p class="custom-block-title">Full Documentation</p><p>For complete API specifications, error codes, and security best practices, please refer to the <a href="./oauth2-guide.html">Integration Guide</a>.</p></div>',13))])}const k=n(h,[["render",u]]);export{v as __pageData,k as default};
